void example_demo(void) {
    Vec2 pts[] = {{1.0f, 2.0f}, {3.0f, 4.0f}};
    FILE *f = fopen("/tmp/kf_vec2.bin", "wb");
    fwrite(pts, sizeof(Vec2), 2, f);
    fclose(f);
    Vec2 loaded[2] = {0};
    f = fopen("/tmp/kf_vec2.bin", "rb");
    fread(loaded, sizeof(Vec2), 2, f);
    fclose(f);
    for (int i = 0; i < 2; i++)
        printf("(%.1f, %.1f)\n", loaded[i].x, loaded[i].y);
